mapper.update:
update t_communicate_memory
begin_time = #{beginTime}, end_time = #{endTime}, communicate_duration = #{communicateDuration}, memory_place = #{memoryPlace}, memory_place_detail = #{memoryPlaceDetail}, memory_images = #{memoryImages}, memory_source = #{memorySource}, row_memory_no = #{rowMemoryNo}, communicator_relation = #{communicatorRelation}, communicator = #{communicator}, communicate_type = #{communicateType}, communicate_way = #{communicateWay}, communicate_content = #{communicateContent}, update_time = now(), update_by = #{updateBy}
where id = #{id}

mapper.select:
select t.id, t.memory_no, t.begin_time, t.end_time, t.communicate_duration, t.memory_owner, t.memory_place, t.memory_place_detail, t.memory_images, t.memory_source, t.row_memory_no, t.update_time, t.update_by, t.communicator_relation, t.communicator, t.communicate_type, t.communicate_way, t.communicate_content, i.name as memoryOwnerName from t_communicate_memory t left join t_sys_person_info i on i.account_id = t.memory_owner
and t.memory_no like concat('%', #{memoryNo}, '%')
and t.communicator like concat('%', #{communicator}, '%')
and t.communicator_relation in
#{item}
and (
FIND_IN_SET(#{item}, t.communicate_type)
)
and t.communicate_way in
#{item}
and t.begin_time >= #{beginTime}
and t.begin_time <= #{endTime}
and t.memory_source in
#{item}
order by t.begin_time desc
